  1→import React, {useCallback, useMemo, useState} from 'react';
  2→import {ActivityIndicator, StyleSheet, Text, View} from 'react-native';
  3→import {
  4→  NavigationContainer,
  5→  DarkTheme,
  6→  DefaultTheme,
  7→} from '@react-navigation/native';
  8→import {createBottomTabNavigator} from '@react-navigation/bottom-tabs';
  9→import {createNativeStackNavigator} from '@react-navigation/native-stack';
 10→import {useQuery} from '@tanstack/react-query';
 11→import {useAuth} from '../features/auth/AuthProvider';
 12→import {useTheme} from '../theme/ThemeProvider';
 13→import {useRealtimeNotifications} from '../hooks/useRealtimeNotifications';
 14→import {socialApi} from '../lib/api/socialApi';
 15→import {Toast} from '../components/Toast';
 16→import {LoginScreen} from '../screens/Auth/LoginScreen';
 17→import {SignUpScreen} from '../screens/Auth/SignUpScreen';
 18→import {ForgotPasswordScreen} from '../screens/Auth/ForgotPasswordScreen';
 19→import {HomeFeedScreen} from '../screens/Home/HomeFeedScreen';
 20→import {ExploreScreen} from '../screens/Home/ExploreScreen';
 21→import {NotificationsScreen} from '../screens/Notifications/NotificationsScreen';
 22→import {ProfileScreen} from '../screens/Profile/ProfileScreen';
 23→import {PostDetailScreen} from '../screens/Home/PostDetailScreen';
 24→import {JournalEditorScreen} from '../screens/Editor/JournalEditorScreen';
 25→import {CanvasScreen} from '../screens/Advanced/CanvasScreen';
 26→import {FreedomWallScreen} from '../screens/Advanced/FreedomWallScreen';
 27→import {UniverseScreen} from '../screens/Advanced/UniverseScreen';
 28→import {StoryBrowserScreen} from '../screens/Stories/StoryBrowserScreen';
 29→import {StoryDetailScreen} from '../screens/Stories/StoryDetailScreen';
 30→import {StoryEditorScreen} from '../screens/Stories/StoryEditorScreen';
 31→import {StoryDashboardScreen} from '../screens/Stories/StoryDashboardScreen';
 32→import {StoryLibraryScreen} from '../screens/Stories/StoryLibraryScreen';
 33→import {StoryChapterManagerScreen} from '../screens/Stories/StoryChapterManagerScreen';
 34→import {StoryChapterEditorScreen} from '../screens/Stories/StoryChapterEditorScreen';
 35→import {StoryChapterReaderScreen} from '../screens/Stories/StoryChapterReaderScreen';
 36→import {
 37→  HomeIcon,
 38→  CompassIcon,
 39→  BookIcon,
 40→  BellIcon,
 41→  UserIcon,
 42→} from '../components/icons';
 43→import type {
 44→  AuthStackParamList,
 45→  MainTabParamList,
 46→  RootStackParamList,
 47→} from './types';
 48→
 49→const RootStack = createNativeStackNavigator<RootStackParamList>();
 50→const AuthStackNav = createNativeStackNavigator<AuthStackParamList>();
 51→const MainTabs = createBottomTabNavigator<MainTabParamList>();
 52→
 53→function AuthNavigator() {
 54→  const {colors} = useTheme();
 55→  return (
 56→    <AuthStackNav.Navigator
 57→      screenOptions={{
 58→        headerStyle: {backgroundColor: colors.bgElevated},
 59→        headerTintColor: colors.textPrimary,
 60→        headerShadowVisible: false,
 61→      }}>
 62→      <AuthStackNav.Screen
 63→        name="Login"
 64→        component={LoginScreen}
 65→        options={{headerShown: false}}
 66→      />
 67→      <AuthStackNav.Screen
 68→        name="SignUp"
 69→        component={SignUpScreen}
 70→        options={{headerShown: false}}
 71→      />
 72→      <AuthStackNav.Screen
 73→        name="ForgotPassword"
 74→        component={ForgotPasswordScreen}
 75→        options={{headerShown: false}}
 76→      />
 77→    </AuthStackNav.Navigator>
 78→  );
 79→}
 80→
 81→function MainTabNavigator() {
 82→  const {colors} = useTheme();
 83→  const {session} = useAuth();
 84→  const token = session?.access_token ?? '';
 85→  const userId = session?.user.id ?? '';
 86→
 87→  const {data: countData} = useQuery({
 88→    queryKey: ['notification-count', userId],
 89→    enabled: Boolean(token && userId),
 90→    queryFn: () => socialApi.getNotificationsCount(token, userId),
 91→    refetchInterval: 30_000,
 92→  });
 93→  const unreadCount = countData?.count ?? 0;
 94→
 95→  return (
 96→    <MainTabs.Navigator
 97→      screenOptions={{
 98→        headerStyle: {backgroundColor: colors.bgPrimary},
 99→        headerTintColor: colors.textPrimary,
100→        headerShadowVisible: false,
101→        tabBarStyle: {
102→          backgroundColor: colors.bgCard,
103→          borderTopColor: colors.borderCard,
104→          borderTopWidth: 1,
105→          elevation: 0,
106→        },
107→        tabBarActiveTintColor: colors.accentAmber,
108→        tabBarInactiveTintColor: colors.textMuted,
109→        tabBarLabelStyle: {
110→          fontSize: 11,
111→          fontWeight: '600',
112→        },
113→      }}>
114→      <MainTabs.Screen
115→        name="Home"
116→        component={HomeFeedScreen}
117→        options={{
118→          headerShown: false,
119→          tabBarIcon: ({color, size}) => <HomeIcon size={size} color={color} />,
120→        }}
121→      />
122→      <MainTabs.Screen
123→        name="Explore"
124→        component={ExploreScreen}
125→        options={{
126→          tabBarIcon: ({color, size}) => <CompassIcon size={size} color={color} />,
127→        }}
128→      />
129→      <MainTabs.Screen
130→        name="Stories"
131→        component={StoryBrowserScreen}
132→        options={{
133→          tabBarIcon: ({color, size}) => <BookIcon size={size} color={color} />,
134→        }}
135→      />
136→      <MainTabs.Screen
137→        name="Notifications"
138→        component={NotificationsScreen}
139→        options={{
140→          tabBarIcon: ({color, size}) => <BellIcon size={size} color={color} />,
141→          tabBarBadge: unreadCount > 0 ? unreadCount : undefined,
142→          tabBarBadgeStyle: {
143→            backgroundColor: colors.accentAmber,
144→            color: '#1A1612',
145→            fontSize: 11,
146→            fontWeight: '700',
147→          },
148→        }}
149→      />
150→      <MainTabs.Screen
151→        name="Profile"
152→        component={ProfileScreen}
153→        options={{
154→          tabBarIcon: ({color, size}) => <UserIcon size={size} color={color} />,
155→        }}
156→      />
157→    </MainTabs.Navigator>
158→  );
159→}
160→
161→function LoggedInShell({children}: {children: React.ReactNode}) {
162→  const {session} = useAuth();
163→  const userId = session?.user.id;
164→  const [toast, setToast] = useState<{message: string; visible: boolean}>({
165→    message: '',
166→    visible: false,
167→  });
168→
169→  const handleNewNotification = useCallback((payload: Record<string, unknown>) => {
170→    const message =
171→      (payload.message as string) || 'You have a new notification';
172→    setToast({message, visible: true});
173→  }, []);
174→
175→  const handleDismissToast = useCallback(() => {
176→    setToast(prev => ({...prev, visible: false}));
177→  }, []);
178→
179→  useRealtimeNotifications(userId, {
180→    onNewNotification: handleNewNotification,
181→  });
182→
183→  return (
184→    <View style={styles.shellContainer}>
185→      {children}
186→      <Toast
187→        message={toast.message}
188→        visible={toast.visible}
189→        onDismiss={handleDismissToast}
190→        type="info"
191→      />
192→    </View>
193→  );
194→}
195→
196→export function RootNavigator() {
197→  const {loading, session} = useAuth();
198→  const {colors, isDark} = useTheme();
199→
200→  const navTheme = useMemo(
201→    () => ({
202→      ...(isDark ? DarkTheme : DefaultTheme),
203→      colors: {
204→        ...(isDark ? DarkTheme.colors : DefaultTheme.colors),
205→        background: colors.bgPrimary,
206→        card: colors.bgElevated,
207→        border: colors.borderLight,
208→        text: colors.textPrimary,
209→        primary: colors.accentAmber,
210→        notification: colors.accentAmber,
211→      },
212→    }),
213→    [colors, isDark],
214→  );
215→
216→  if (loading) {
217→    return (
218→      <View style={[styles.loadingContainer, {backgroundColor: colors.bgPrimary}]}>
219→        <ActivityIndicator color={colors.loaderColor} />
220→        <Text style={[styles.loadingText, {color: colors.textMuted}]}>
221→          Loading session...
222→        </Text>
223→      </View>
224→    );
225→  }
226→
227→  return (
228→    <NavigationContainer theme={navTheme}>
229→      <RootStack.Navigator
230→        screenOptions={{
231→          headerStyle: {backgroundColor: colors.bgElevated},
232→          headerTintColor: colors.textPrimary,
233→          headerShadowVisible: false,
234→          contentStyle: {backgroundColor: colors.bgPrimary},
235→        }}>
236→        {!session ? (
237→          <RootStack.Screen
238→            name="Auth"
239→            component={AuthNavigator}
240→            options={{headerShown: false}}
241→          />
242→        ) : (
243→          <>
244→            <RootStack.Screen
245→              name="Main"
246→              options={{headerShown: false}}>
247→              {() => (
248→                <LoggedInShell>
249→                  <MainTabNavigator />
250→                </LoggedInShell>
251→              )}
252→            </RootStack.Screen>
253→            <RootStack.Screen
254→              name="PostDetail"
255→              component={PostDetailScreen}
256→              options={{title: 'Post'}}
257→            />
258→            <RootStack.Screen
259→              name="JournalEditor"
260→              component={JournalEditorScreen}
261→              options={{title: 'Journal Editor'}}
262→            />
263→            <RootStack.Screen
264→              name="StoryDetail"
265→              component={StoryDetailScreen}
266→              options={{title: 'Story'}}
267→            />
268→            <RootStack.Screen
269→              name="StoryEditor"
270→              component={StoryEditorScreen}
271→              options={{title: 'Story Editor'}}
272→            />
273→            <RootStack.Screen
274→              name="StoryDashboard"
275→              component={StoryDashboardScreen}
276→              options={{title: 'My Stories'}}
277→            />
278→            <RootStack.Screen
279→              name="StoryLibrary"
280→              component={StoryLibraryScreen}
281→              options={{title: 'Story Library'}}
282→            />
283→            <RootStack.Screen
284→              name="StoryChapterManager"
285→              component={StoryChapterManagerScreen}
286→              options={{title: 'Chapter Manager'}}
287→            />
288→            <RootStack.Screen
289→              name="StoryChapterEditor"
290→              component={StoryChapterEditorScreen}
291→              options={{title: 'Chapter Editor'}}
292→            />
293→            <RootStack.Screen
294→              name="StoryChapterReader"
295→              component={StoryChapterReaderScreen}
296→              options={{title: 'Chapter'}}
297→            />
298→            <RootStack.Screen name="Canvas" component={CanvasScreen} />
299→            <RootStack.Screen
300→              name="FreedomWall"
301→              component={FreedomWallScreen}
302→              options={{title: 'Freedom Wall'}}
303→            />
304→            <RootStack.Screen name="Universe" component={UniverseScreen} />
305→          </>
306→        )}
307→      </RootStack.Navigator>
308→    </NavigationContainer>
309→  );
310→}
311→
312→const styles = StyleSheet.create({
313→  shellContainer: {
314→    flex: 1,
315→  },
316→  loadingContainer: {
317→    flex: 1,
318→    justifyContent: 'center',
319→    alignItems: 'center',
320→    gap: 8,
321→  },
322→  loadingText: {
323→    fontSize: 14,
324→  },
325→});
