  1→import React, { createContext, useContext, useEffect, useMemo, useState } from 'react';
  2→import type { AuthChangeEvent, Session, User } from '@supabase/supabase-js';
  3→import { IS_SUPABASE_CONFIGURED } from '../../config/env';
  4→import * as supabaseModule from '../../lib/supabase';
  5→
  6→type Credentials = {
  7→  email: string;
  8→  password: string;
  9→};
 10→
 11→type AuthContextValue = {
 12→  user: User | null;
 13→  session: Session | null;
 14→  loading: boolean;
 15→  authError: string | null;
 16→  signIn: (credentials: Credentials) => Promise<void>;
 17→  signUp: (credentials: Credentials) => Promise<void>;
 18→  signOut: () => Promise<void>;
 19→};
 20→
 21→const AuthContext = createContext<AuthContextValue | undefined>(undefined);
 22→
 23→const notConfiguredMessage =
 24→  'Supabase is not configured. Set ISK_MOBILE_SUPABASE_URL and ISK_MOBILE_SUPABASE_ANON_KEY before using auth flows.';
 25→const unavailableClientMessage =
 26→  'Supabase client is unavailable. Restart Metro with --reset-cache and relaunch the app.';
 27→
 28→const supabase = supabaseModule?.supabase;
 29→
 30→const resolveAuthClient = () => {
 31→  if (!IS_SUPABASE_CONFIGURED) {
 32→    throw new Error(notConfiguredMessage);
 33→  }
 34→  if (!supabase) {
 35→    throw new Error(unavailableClientMessage);
 36→  }
 37→
 38→  return supabase.auth;
 39→};
 40→
 41→export function AuthProvider({ children }: { children: React.ReactNode }) {
 42→  const [session, setSession] = useState<Session | null>(null);
 43→  const [loading, setLoading] = useState(true);
 44→  const [authError, setAuthError] = useState<string | null>(null);
 45→
 46→  useEffect(() => {
 47→    let mounted = true;
 48→
 49→    if (!IS_SUPABASE_CONFIGURED) {
 50→      setAuthError(notConfiguredMessage);
 51→      setLoading(false);
 52→      return () => {
 53→        mounted = false;
 54→      };
 55→    }
 56→
 57→    if (!supabase) {
 58→      setAuthError(unavailableClientMessage);
 59→      setLoading(false);
 60→      return () => {
 61→        mounted = false;
 62→      };
 63→    }
 64→
 65→    setAuthError(null);
 66→
 67→    (async () => {
 68→      try {
 69→        const { data, error } = await supabase.auth.getSession();
 70→        if (!mounted) {
 71→          return;
 72→        }
 73→
 74→        if (error) {
 75→          setAuthError(error.message);
 76→        } else {
 77→          setAuthError(null);
 78→        }
 79→
 80→        setSession(data.session ?? null);
 81→      } catch (error) {
 82→        if (!mounted) {
 83→          return;
 84→        }
 85→
 86→        setAuthError(error instanceof Error ? error.message : 'Failed to load auth session.');
 87→      } finally {
 88→        if (mounted) {
 89→          setLoading(false);
 90→        }
 91→      }
 92→    })();
 93→
 94→    const {
 95→      data: { subscription },
 96→    } = supabase.auth.onAuthStateChange((_event: AuthChangeEvent, nextSession: Session | null) => {
 97→      setSession(nextSession);
 98→      setAuthError(null);
 99→    });
100→
101→    return () => {
102→      mounted = false;
103→      subscription.unsubscribe();
104→    };
105→  }, []);
106→
107→  const value = useMemo<AuthContextValue>(
108→    () => ({
109→      user: session?.user ?? null,
110→      session,
111→      loading,
112→      authError,
113→      signIn: async ({ email, password }) => {
114→        const auth = resolveAuthClient();
115→        setAuthError(null);
116→
117→        try {
118→          const { error } = await auth.signInWithPassword({ email, password });
119→          if (error) {
120→            throw error;
121→          }
122→        } catch (error) {
123→          const message = error instanceof Error ? error.message : 'Sign in failed.';
124→          setAuthError(message);
125→          throw error;
126→        }
127→      },
128→      signUp: async ({ email, password }) => {
129→        const auth = resolveAuthClient();
130→        setAuthError(null);
131→
132→        try {
133→          const { error } = await auth.signUp({ email, password });
134→          if (error) {
135→            throw error;
136→          }
137→        } catch (error) {
138→          const message = error instanceof Error ? error.message : 'Sign up failed.';
139→          setAuthError(message);
140→          throw error;
141→        }
142→      },
143→      signOut: async () => {
144→        const auth = resolveAuthClient();
145→        setAuthError(null);
146→
147→        try {
148→          const { error } = await auth.signOut();
149→          if (error) {
150→            throw error;
151→          }
152→        } catch (error) {
153→          const message = error instanceof Error ? error.message : 'Sign out failed.';
154→          setAuthError(message);
155→          throw error;
156→        }
157→      },
158→    }),
159→    [authError, loading, session],
160→  );
161→
162→  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
163→}
164→
165→export function useAuth() {
166→  const context = useContext(AuthContext);
167→  if (!context) {
168→    throw new Error('useAuth must be used within AuthProvider');
169→  }
170→
171→  return context;
172→}
